1:/**
2: * Arbor — the guild runtime.
3: *
4: * `createGuild()` is the single entry point. It reads guild.json, loads all
5: * declared plugins, validates dependencies, starts apparatus in order, wires
6: * the guild() singleton, and returns the Guild object.
7: *
8: * The full plugin lifecycle:
9: *   1. Load    — imports all declared plugin packages, discriminates kit vs apparatus
10: *   2. Validate — checks `requires` declarations, detects circular dependencies
11: *   3. Start   — calls start(ctx) on each apparatus in dependency-resolved order
12: *   4. Events  — fires `plugin:initialized` after each plugin loads
13: *   5. Warn    — advisory warnings for mismatched kit contributions / recommends
14: *
15: * Pure logic (validation, ordering, events) lives in guild-lifecycle.ts.
16: * This file handles I/O and orchestration.
17: */
19:import {
20:  readGuildConfig,
21:  writeGuildConfig,
22:  findGuildRoot,
23:  isKit,
24:  isApparatus,
25:  setGuild,
26:  resolveGuildPackageEntry,
27:  resolvePackageNameForPluginId,
28:  readGuildPackageJson,
29:} from '@shardworks/nexus-core';
30:import type {
31:  Guild,
32:  LoadedKit,
33:  LoadedApparatus,
34:  FailedPlugin,
35:} from '@shardworks/nexus-core';
37:import {
38:  validateRequires,
39:  filterFailedPlugins,
40:  topoSort,
41:  collectStartupWarnings,
42:  buildStartupContext,
43:  fireEvent,
44:} from './guild-lifecycle.ts';
45:import type { EventHandlerMap } from './guild-lifecycle.ts';
47:// ── Public API ────────────────────────────────────────────────────────
49:/**
50: * Create and start a guild.
51: *
52: * Reads guild.json, loads all declared plugins, validates dependencies,
53: * starts apparatus in dependency order, and returns the Guild object.
54: * Also sets the guild() singleton so apparatus code can access it.
55: *
56: * @param root - Absolute path to the guild root. Defaults to auto-detection
57: *               by walking up from cwd until guild.json is found.
58: * @returns The initialized Guild — the same object guild() returns.
59: */
60:export async function createGuild(root?: string): Promise<Guild> {
61:  const guildRoot = root ?? findGuildRoot();
62:  const config = readGuildConfig(guildRoot);
64:  const kits:        LoadedKit[]        = [];
65:  const apparatuses: LoadedApparatus[]  = [];
66:  const eventHandlers: EventHandlerMap = new Map();
68:  // ── Load phase ─────────────────────────────────────────────────────
70:  for (const pluginId of config.plugins) {
71:    const packageName = resolvePackageNameForPluginId(guildRoot, pluginId);
72:    if (!packageName) {
73:      console.warn(`[arbor] No package found in package.json for plugin "${pluginId}" — skipping`);
74:      continue;
75:    }
77:    const { version } = readGuildPackageJson(guildRoot, packageName);
79:    try {
80:      const entryPath = resolveGuildPackageEntry(guildRoot, packageName);
81:      const mod = await import(entryPath) as { default: unknown };
82:      const raw = mod.default;
84:      if (isApparatus(raw)) {
85:        apparatuses.push({ packageName, id: pluginId, version, apparatus: raw.apparatus });
86:      } else if (isKit(raw)) {
87:        kits.push({ packageName, id: pluginId, version, kit: raw.kit });
88:      } else {
89:        console.warn(
90:          `[arbor] Plugin "${packageName}" does not export a kit or apparatus — skipping. ` +
91:          `Plugins must export { kit: ... } or { apparatus: ... }.`,
92:        );
93:      }
94:    } catch (err) {
95:      const message = err instanceof Error ? err.message : String(err);
96:      console.warn(`[arbor] Failed to load plugin "${packageName}": ${message}`);
97:    }
98:  }
100:  // ── Validation phase ───────────────────────────────────────────────
102:  const allFailures: FailedPlugin[] = [];
104:  const rootFailures = validateRequires(kits, apparatuses);
105:  allFailures.push(...rootFailures);
107:  // Remove plugins that transitively depend on failed ones
108:  if (rootFailures.length > 0) {
109:    const filtered = filterFailedPlugins(kits, apparatuses, rootFailures);
110:    kits.length = 0;
111:    kits.push(...filtered.kits);
112:    apparatuses.length = 0;
113:    apparatuses.push(...filtered.apparatuses);
114:    allFailures.push(...filtered.cascaded);
116:    for (const f of allFailures) {
117:      console.warn(`[arbor] ${f.reason}`);
118:    }
119:  }
121:  // ── Startup warnings ───────────────────────────────────────────────
123:  const allWarnings = collectStartupWarnings(kits, apparatuses);
124:  for (const warning of allWarnings) {
125:    console.warn(warning);
126:  }
128:  // ── Start phase ────────────────────────────────────────────────────
130:  const orderedApparatuses = topoSort(apparatuses);
131:  const provides = new Map<string, unknown>();
133:  // Wire guild singleton before any apparatus starts so start() methods
134:  // can call guild(). The provides Map is populated progressively as each
135:  // apparatus starts; dependency ordering guarantees declared deps are
136:  // available.
138:  const guildInstance: Guild = {
139:    home: guildRoot,
141:    apparatus<T>(name: string): T {
142:      const p = provides.get(name);
143:      if (p === undefined) {
144:        throw new Error(
145:          `[guild] apparatus("${name}") is not available. ` +
146:          `No loaded apparatus provides this id. Check guild.json plugins list.`,
147:        );
148:      }
149:      return p as T;
150:    },
152:    config<T = Record<string, unknown>>(pluginId: string): T {
153:      // GuildConfig types only the framework-level keys (name, nexus, plugins, etc.).
154:      // Plugin-specific config sections (e.g. "animator", "stacks") are additional
155:      // top-level keys in guild.json that GuildConfig doesn't model. The cast is safe
156:      // because guild.json is a plain JSON object — all keys are accessible at runtime.
157:      // Plugins can use module augmentation on GuildConfig to get typed access; this
158:      // generic path remains the untyped fallback.
159:      const cfg = config as unknown as Record<string, unknown>;
160:      return (cfg[pluginId] ?? {}) as T;
161:    },
163:    writeConfig<T = Record<string, unknown>>(pluginId: string, value: T): void {
164:      // Update the in-memory config so subsequent reads reflect the change,
165:      // then persist to disk. The cast is the same pattern as config() above.
166:      const cfg = config as unknown as Record<string, unknown>;
167:      cfg[pluginId] = value;
168:      writeGuildConfig(guildRoot, config);
169:    },
171:    guildConfig() {
172:      return config;
173:    },
175:    kits()             { return [...kits]; },
176:    apparatuses()      { return [...orderedApparatuses]; },
177:    failedPlugins()    { return [...allFailures]; },
178:    startupWarnings()  { return [...allWarnings]; },
179:  };
180:  setGuild(guildInstance);
182:  // Fire plugin:initialized for all kits before starting any apparatus
183:  for (const kit of kits) {
184:    await fireEvent(eventHandlers, 'plugin:initialized', kit);
185:  }
187:  // Start each apparatus in dependency order
188:  const startupCtx = buildStartupContext(eventHandlers);
189:  for (const app of orderedApparatuses) {
190:    // Register provides before start() so apparatuses with eager provides are
191:    // visible to later startups that run during this loop.
192:    if (app.apparatus.provides !== undefined) {
193:      provides.set(app.id, app.apparatus.provides);
194:    }
196:    await app.apparatus.start(startupCtx);
198:    // Re-check after start() for deferred provides (e.g. Stacks uses a getter
199:    // that returns undefined until start() populates the backing variable).
200:    if (!provides.has(app.id) && app.apparatus.provides !== undefined) {
201:      provides.set(app.id, app.apparatus.provides);
202:    }
204:    await fireEvent(eventHandlers, 'plugin:initialized', app);
205:  }
207:  return guildInstance;
208:}

