4	 * The Loom owns system prompt assembly. Given a role name, it produces
5	 * an AnimaWeave — the composed identity context that The Animator uses
6	 * to launch a session. The work prompt (what the anima should do) is
7	 * not the Loom's concern; it bypasses the Loom and goes directly to
8	 * the Animator.
9	 *
10	 * The Loom resolves the role's permission grants from guild.json, then
11	 * calls the Instrumentarium to resolve the permission-gated tool set.
12	 * Tools are returned on the AnimaWeave so the Animator can pass them
13	 * to the session provider for MCP server configuration.
14	 *
15	 * See: docs/specification.md (loom)
16	 */
17	
18	import type { Plugin, StartupContext, LoadedPlugin } from '@shardworks/nexus-core';
19	import { guild, isLoadedApparatus } from '@shardworks/nexus-core';
20	import type { InstrumentariumApi, ResolvedTool } from '@shardworks/tools-apparatus';
21	import { tool } from '@shardworks/tools-apparatus';
22	import { z } from 'zod';
23	import fs from 'node:fs';
24	import path from 'node:path';
25	
26	// ── Public types ──────────────────────────────────────────────────────
27	
28	export interface WeaveRequest {
29	  /**
30	   * The role to weave context for (e.g. 'artificer', 'scribe').
31	   *
32	   * When provided, the Loom resolves role → permissions from guild.json,
33	   * then calls the Instrumentarium to resolve the permission-gated tool set.
34	   * Tools are returned on the AnimaWeave.
35	   *
36	   * When omitted, no tool resolution occurs — the AnimaWeave has no tools.
37	   */
38	  role?: string;
39	}
40	
41	/**
42	 * The output of The Loom's weave() — the composed anima identity context.
43	 *
44	 * Contains the system prompt (produced by the Loom from the anima's
45	 * identity layers) and the resolved tool set for the role. The work
46	 * prompt is not part of the weave — it goes directly to the Animator.
47	 */
48	export interface AnimaWeave {
49	  /**
50	   * The system prompt for the AI process. Composed from guild charter,
51	   * tool instructions, and role instructions. Undefined when no
52	   * composition layers produce content.
53	   */
54	  systemPrompt?: string;
55	  /** The resolved tool set for this role. Undefined when no role is specified or no tools match. */
56	  tools?: ResolvedTool[];
57	  /** Environment variables derived from role identity (e.g. git author/committer). */
58	  environment?: Record<string, string>;
59	}
60	
61	/** Metadata for a registered role, returned by listRoles(). */
62	export interface RoleInfo {
63	  /** Role name — the value you pass to weave({ role }). Qualified for kit roles (e.g. 'animator.scribe'). */
64	  name: string;
65	  /** Permission grants in plugin:level format. */
66	  permissions: string[];
67	  /** When true, permissionless tools are excluded unless the role grants plugin:* or *:*. */
68	  strict?: boolean;
69	  /** Source of the role definition: 'guild' for guild.json roles, or the plugin ID for kit-contributed roles. */
70	  source: string;
71	}
72	
73	/** The Loom's public API, exposed via `provides`. */
74	export interface LoomApi {
75	  /**
76	   * Weave an anima's session context.
77	   *
78	   * Given a role name, produces an AnimaWeave containing the composed
79	   * system prompt and the resolved tool set. The system prompt is assembled
80	   * from the guild charter, tool instructions (for the resolved tool set),
81	   * and role instructions — in that order.
82	   *
83	   * Tool resolution is active: if a role is provided and the Instrumentarium
84	   * is installed, the Loom resolves role → permissions → tools.
85	   */
86	  weave(request: WeaveRequest): Promise<AnimaWeave>;
87	  /** List all registered roles with their metadata. */
88	  listRoles(): RoleInfo[];
89	}
90	
91	// ── Config types ─────────────────────────────────────────────────────
92	
93	/** Role definition in guild.json under the Loom's plugin section. */
94	export interface RoleDefinition {
95	  /** Permission grants in `plugin:level` format. */
96	  permissions: string[];
97	  /**
98	   * When true, permissionless tools are excluded unless the role grants
99	   * `plugin:*` or `*:*` for the tool's plugin. Default: false.
100	   */
101	  strict?: boolean;
102	}
103	
104	/** Loom configuration from guild.json. */
105	export interface LoomConfig {
106	  /** Role definitions keyed by role name. */
107	  roles?: Record<string, RoleDefinition>;
108	}
109	
110	/** Role definition contributed by a kit or apparatus supportKit. */
111	export interface KitRoleDefinition {
112	  /** Permission grants in `plugin:level` format. */
113	  permissions: string[];
114	  /**
115	   * When true, permissionless tools are excluded unless the role grants
116	   * `plugin:*` or `*:*` for the tool's plugin. Default: false.
117	   */
118	  strict?: boolean;
119	  /** Inline role instructions injected into the system prompt. */
120	  instructions?: string;
121	  /**
122	   * Path to an instructions file, relative to the kit's npm package root.
123	   * Resolved at registration time. Mutually exclusive with `instructions`
124	   * (if both are present, `instructions` wins).
125	   */
126	  instructionsFile?: string;
127	}
128	
129	/** Kit contribution interface for role definitions. */
130	export interface LoomKit {
131	  roles?: Record<string, KitRoleDefinition>;
132	}
133	
134	// ── Apparatus factory ─────────────────────────────────────────────────
135	
136	/**
137	 * Create the Loom apparatus plugin.
138	 *
139	 * Returns a Plugin with:
140	 * - `requires: ['tools']` — needs the Instrumentarium for tool resolution
141	 * - `consumes: ['roles']` — declares that the Loom consumes kit role contributions
142	 * - `provides: LoomApi` — the context composition API
143	 */
144	export function createLoom(): Plugin {
145	  let config: LoomConfig = {};
146	  let charterContent: string | undefined;
147	  let roleInstructions: Map<string, string> = new Map();
148	  let kitRoles: Map<string, RoleDefinition> = new Map();
149	
150	  function registerKitRoles(
151	    pluginId: string,
152	    packageName: string,
153	    kit: Record<string, unknown>,
154	    home: string,
155	  ): void {
156	    const rawRoles = kit.roles;
157	    if (typeof rawRoles !== 'object' || rawRoles === null || Array.isArray(rawRoles)) return;
158	
159	    // Compute allowed plugin IDs for dependency-scoped validation
160	    const allowedPlugins = new Set<string>([
161	      pluginId,
162	      ...((kit.requires as string[] | undefined) ?? []),
163	      ...((kit.recommends as string[] | undefined) ?? []),
164	    ]);
165	
166	    for (const [roleName, rawDef] of Object.entries(rawRoles as Record<string, unknown>)) {
167	      // Skip non-object entries silently
168	      if (typeof rawDef !== 'object' || rawDef === null || Array.isArray(rawDef)) continue;
169	
170	      const def = rawDef as Record<string, unknown>;
171	
172	      // Validate permissions field exists and is an array
173	      if (!Array.isArray(def.permissions)) {
174	        console.warn(
175	          `[loom] Kit "${pluginId}" role "${roleName}" is missing required "permissions" array — skipped`,
176	        );
177	        continue;
178	      }
179	
180	      const qualifiedName = `${pluginId}.${roleName}`;
181	
182	      // Guild override check at registration time — skip if guild defines this role
183	      if (config.roles && config.roles[qualifiedName]) continue;
184	
185	      // Dependency-scoped permission filtering
186	      const validPermissions: string[] = [];
187	      for (const perm of def.permissions as string[]) {
188	        if (typeof perm !== 'string') continue;
189	        const colonIdx = perm.indexOf(':');
190	        if (colonIdx === -1) {
191	          console.warn(
192	            `[loom] Kit "${pluginId}" role "${roleName}" permission "${perm}" has no colon separator — dropped`,
193	          );
194	          continue;
195	        }
196	        const permPluginId = perm.slice(0, colonIdx);
197	        if (permPluginId === '*' || !allowedPlugins.has(permPluginId)) {
198	          console.warn(
199	            `[loom] Kit "${pluginId}" role "${roleName}" permission "${perm}" references undeclared plugin "${permPluginId}" — dropped`,
200	          );
201	          continue;
202	        }
203	        validPermissions.push(perm);
204	      }
205	
206	      // Register the role
207	      kitRoles.set(qualifiedName, {
208	        permissions: validPermissions,
209	        ...(def.strict === true ? { strict: true } : {}),
210	      });
211	
212	      // Resolve instructions — inline takes precedence over file
213	      if (typeof def.instructions === 'string' && def.instructions) {
214	        roleInstructions.set(qualifiedName, def.instructions);
215	      } else if (typeof def.instructionsFile === 'string' && def.instructionsFile) {
216	        const filePath = path.join(home, 'node_modules', packageName, def.instructionsFile);
217	        try {
218	          const content = fs.readFileSync(filePath, 'utf-8');
219	          if (content) {
220	            roleInstructions.set(qualifiedName, content);
221	          }
222	        } catch {
223	          console.warn(
224	            `[loom] Could not read instructions file for kit "${pluginId}" role "${roleName}": ${filePath}`,
225	          );
226	        }
227	      }
228	    }
229	  }
230	
231	  const api: LoomApi = {
232	    listRoles(): RoleInfo[] {
233	      const roles: RoleInfo[] = [];
234	
235	      // Guild roles first
236	      if (config.roles) {
237	        for (const [name, def] of Object.entries(config.roles)) {
238	          roles.push({
239	            name,
240	            permissions: def.permissions,
241	            ...(def.strict === true ? { strict: true } : {}),
242	            source: 'guild',
243	          });
244	        }
245	      }
246	
247	      // Kit roles after
248	      for (const [name, def] of kitRoles.entries()) {
249	        const dotIdx = name.indexOf('.');
250	        const source = dotIdx !== -1 ? name.slice(0, dotIdx) : name;
251	        roles.push({
252	          name,
253	          permissions: def.permissions,
254	          ...(def.strict === true ? { strict: true } : {}),
255	          source,
256	        });
257	      }
258	
259	      return roles;
260	    },
261	
262	    async weave(request: WeaveRequest): Promise<AnimaWeave> {
263	      const weave: AnimaWeave = {};
264	
265	      // Resolve tools if a role is provided and has a definition.
266	      // Guild-defined roles take precedence over kit-contributed roles.
267	      if (request.role) {
268	        const roleDef = config.roles?.[request.role] ?? kitRoles.get(request.role);
269	        if (roleDef) {
270	          try {
271	            const instrumentarium = guild().apparatus<InstrumentariumApi>('tools');
272	            weave.tools = instrumentarium.resolve({
273	              permissions: roleDef.permissions,
274	              strict: roleDef.strict,
275	              caller: 'anima',
276	            });
277	          } catch {
278	            // Instrumentarium not installed — no tools.
279	            // This shouldn't happen since we require 'tools', but
280	            // fail gracefully rather than crash the session.
281	          }
282	        }
283	      }
284	
285	      // Derive git identity from role name.
286	      if (request.role) {
287	        const displayName = request.role.charAt(0).toUpperCase() + request.role.slice(1);
288	        weave.environment = {
289	          GIT_AUTHOR_NAME: displayName,
290	          GIT_AUTHOR_EMAIL: `${request.role}@nexus.local`,
291	        };
292	      }
293	
294	      // Compose system prompt from available layers: charter → tool instructions → role instructions.
295	      const layers: string[] = [];
296	
297	      if (charterContent) {
298	        layers.push(charterContent);
299	      }
300	
301	      if (weave.tools && weave.tools.length > 0) {
302	        for (const resolvedTool of weave.tools) {
303	          const instructions = resolvedTool.definition.instructions;
304	          if (instructions) {
305	            layers.push(`## Tool: ${resolvedTool.definition.name}\n\n${instructions}`);
306	          }
307	        }
308	      }
309	
310	      if (request.role && roleInstructions.has(request.role)) {
311	        layers.push(roleInstructions.get(request.role)!);
312	      }
313	
314	      if (layers.length > 0) {
315	        weave.systemPrompt = layers.join('\n\n');
316	      }
317	
318	      return weave;
319	    },
320	  };
321	
322	  // ── Patron-callable introspection tools ──────────────────────────────
323	
324	  const loomRolesTool = tool({
325	    name: 'loom-roles',
326	    description: 'List all roles and their configuration',
327	    params: {},
328	    handler: async () => api.listRoles(),
329	  });
330	
331	  const loomWeaveTool = tool({
332	    name: 'loom-weave',
333	    description: 'Preview the weave result for a role',
334	    params: {
335	      role: z.string().describe('Role name to weave'),
336	    },
337	    handler: async ({ role }) => {
338	      const weave = await api.weave({ role });
339	      return {
340	        systemPrompt: weave.systemPrompt,
341	        tools: weave.tools?.map(t => ({
342	          name: t.definition.name,
343	          description: t.definition.description,
344	          permission: t.definition.permission,
345	          pluginId: t.pluginId,
346	        })),
347	        environment: weave.environment,
348	      };
349	    },
350	  });
351	
352	  return {
353	    apparatus: {
354	      requires: ['tools'],
355	      recommends: ['oculus'],
356	      consumes: ['roles'],
357	      provides: api,
358	
359	      supportKit: {
360	        tools: [loomRolesTool, loomWeaveTool],
361	        pages: [{ id: 'loom', title: 'Roles', dir: 'pages/loom' }],
362	      },
363	
364	      start(ctx: StartupContext): void {
365	        const g = guild();
366	        config = g.guildConfig().loom ?? {};
367	        const home = g.home;
368	
369	        // Read charter content at startup and cache it.
370	        charterContent = undefined;
371	        const charterFilePath = path.join(home, 'charter.md');
372	        try {
373	          charterContent = fs.readFileSync(charterFilePath, 'utf-8');
374	        } catch (err: unknown) {
375	          if ((err as NodeJS.ErrnoException).code !== 'ENOENT') throw err;
376	          // No charter.md — check for charter/ directory.
377	          const charterDir = path.join(home, 'charter');
378	          try {
379	            const stat = fs.statSync(charterDir);
380	            if (stat.isDirectory()) {
381	              const mdFiles = fs.readdirSync(charterDir)
382	                .filter(f => f.endsWith('.md'))
383	                .sort();
384	              if (mdFiles.length > 0) {
385	                charterContent = mdFiles
386	                  .map(f => fs.readFileSync(path.join(charterDir, f), 'utf-8'))
387	                  .join('\n\n');
388	              }
389	            }
390	          } catch {
391	            // No charter/ directory either — silently omit.
392	          }
393	        }
394	
395	        // Read role instruction files at startup for all configured (guild) roles.
396	        roleInstructions = new Map();
397	        if (config.roles) {
398	          for (const roleName of Object.keys(config.roles)) {
399	            const rolePath = path.join(home, 'roles', `${roleName}.md`);
400	            try {
401	              const content = fs.readFileSync(rolePath, 'utf-8');
402	              if (content) {
403	                roleInstructions.set(roleName, content);
404	              }
405	            } catch {
406	              // File doesn't exist — silently omit.
407	            }
408	          }
409	        }
410	
411	        // ── Kit role scanning ──────────────────────────────────────────
412	        kitRoles = new Map();
413	
414	        // Phase 1a: Scan all already-loaded standalone kits.
415	        for (const kit of g.kits()) {
416	          registerKitRoles(kit.id, kit.packageName, kit.kit, home);
417	        }
418	
419	        // Phase 1b: Scan already-started apparatus for supportKit roles.
420	        // The Loom requires ['tools'], so apparatus that started before it
421	        // (e.g. Instrumentarium) have already fired plugin:initialized.
422	        for (const app of g.apparatuses()) {
423	          if (app.apparatus.supportKit) {
424	            registerKitRoles(app.id, app.packageName, app.apparatus.supportKit, home);
425	          }
426	        }
427	
428	        // Phase 2: Subscribe to plugin:initialized for apparatus supportKits
429	        // that start after the Loom in the dependency order.
430	        ctx.on('plugin:initialized', (plugin: unknown) => {
431	          const loaded = plugin as LoadedPlugin;
432	          if (isLoadedApparatus(loaded) && loaded.apparatus.supportKit) {
433	            registerKitRoles(loaded.id, loaded.packageName, loaded.apparatus.supportKit, home);
434	          }
435	        });
436	      },
437	    },
438	  };
439	}
