1	/**
2	 * The Clerk — writ lifecycle management apparatus.
3	 *
4	 * The Clerk manages the lifecycle of writs: lightweight work orders that flow
5	 * through a fixed status machine (ready → active → completed/failed, or
6	 * ready/active → cancelled). Each writ has a type, a title, a body, and
7	 * optional codex and resolution fields.
8	 *
9	 * Writ types are validated against the guild config's writTypes field plus the
10	 * built-in type ('mandate'). An unknown type is rejected at post time.
11	 * Kits may also contribute writ types via their writTypes field.
12	 *
13	 * See: docs/architecture/apparatus/clerk.md
14	 */
15	
16	import type { Plugin, StartupContext, LoadedPlugin } from '@shardworks/nexus-core';
17	import { guild, generateId, isLoadedApparatus } from '@shardworks/nexus-core';
18	import { tool } from '@shardworks/tools-apparatus';
19	import type { StacksApi, Book, WhereClause } from '@shardworks/stacks-apparatus';
20	
21	import type {
22	  ClerkApi,
23	  ClerkConfig,
24	  WritDoc,
25	  WritLinkDoc,
26	  WritLinks,
27	  WritStatus,
28	  PostCommissionRequest,
29	  WritFilters,
30	  WritTypeEntry,
31	} from './types.ts';
32	
33	import {
34	  commissionPost,
35	  writShow,
36	  writList,
37	  writAccept,
38	  writComplete,
39	  writFail,
40	  writCancel,
41	  writLink,
42	  writUnlink,
43	} from './tools/index.ts';
44	
45	// ── Kit contribution interface ────────────────────────────────────────
46	
47	/** Kit contribution interface for the Clerk's writ type system. */
48	export interface ClerkKit {
49	  /** Writ type descriptors to register with the Clerk. Names are unqualified. */
50	  writTypes?: WritTypeEntry[];
51	}
52	
53	// ── Built-in writ types ──────────────────────────────────────────────
54	
55	const BUILTIN_TYPES = new Set(['mandate']);
56	
57	// ── Status machine ───────────────────────────────────────────────────
58	
59	const ALLOWED_FROM: Record<WritStatus, WritStatus[]> = {
60	  active: ['ready'],
61	  completed: ['active'],
62	  failed: ['active'],
63	  cancelled: ['ready', 'active'],
64	  ready: [],
65	};
66	
67	const TERMINAL_STATUSES = new Set<WritStatus>(['completed', 'failed', 'cancelled']);
68	
69	// ── Factory ──────────────────────────────────────────────────────────
70	
71	export function createClerk(): Plugin {
72	  let writs: Book<WritDoc>;
73	  let links: Book<WritLinkDoc>;
74	
75	  /** Merged set of valid writ type names: builtins + config + kit contributions. */
76	  let mergedWritTypes: Set<string> = new Set(BUILTIN_TYPES);
77	
78	  /** Config-declared writ type names, for override checking during kit registration. */
79	  let configWritTypeNames: Set<string> = new Set();
80	
81	  // ── Helpers ──────────────────────────────────────────────────────
82	
83	  function resolveClerkConfig(): ClerkConfig {
84	    return guild().guildConfig().clerk ?? {};
85	  }
86	
87	  function resolveWritTypes(): Set<string> {
88	    return mergedWritTypes;
89	  }
90	
91	  function resolveDefaultType(): string {
92	    const config = resolveClerkConfig();
93	    return config.defaultType ?? 'mandate';
94	  }
95	
96	  function buildWhereClause(filters?: WritFilters): WhereClause | undefined {
97	    const conditions: WhereClause = [];
98	    if (filters?.status) {
99	      conditions.push(['status', '=', filters.status]);
100	    }
101	    if (filters?.type) {
102	      conditions.push(['type', '=', filters.type]);
103	    }
104	    return conditions.length > 0 ? conditions : undefined;
105	  }
106	
107	  function registerKitWritTypes(pluginId: string, kit: Record<string, unknown>): void {
108	    const raw = kit.writTypes;
109	    if (!Array.isArray(raw)) return;
110	
111	    for (const entry of raw) {
112	      if (
113	        typeof entry !== 'object' ||
114	        entry === null ||
115	        typeof (entry as Record<string, unknown>).name !== 'string'
116	      ) {
117	        console.warn(
118	          `[clerk] Kit "${pluginId}" writTypes: entry is missing required "name" field — skipped`
119	        );
120	        continue;
121	      }
122	      const name = (entry as WritTypeEntry).name;
123	
124	      // Config override: skip silently
125	      if (configWritTypeNames.has(name)) continue;
126	
127	      // Duplicate kit contribution: first wins, warn
128	      if (mergedWritTypes.has(name)) {
129	        console.warn(
130	          `[clerk] Kit "${pluginId}" writTypes: type "${name}" already registered by another kit — skipped`
131	        );
132	        continue;
133	      }
134	
135	      mergedWritTypes.add(name);
136	    }
137	  }
138	
139	  // ── API ──────────────────────────────────────────────────────────
140	
141	  const api: ClerkApi = {
142	    async post(request: PostCommissionRequest): Promise<WritDoc> {
143	      const type = request.type ?? resolveDefaultType();
144	      const validTypes = resolveWritTypes();
145	
146	      if (!validTypes.has(type)) {
147	        throw new Error(
148	          `Unknown writ type "${type}". Declared types: ${[...validTypes].join(', ')}.`,
149	        );
150	      }
151	
152	      const now = new Date().toISOString();
153	      const writ: WritDoc = {
154	        id: generateId('w', 6),
155	        type,
156	        status: 'ready',
157	        title: request.title,
158	        body: request.body,
159	        ...(request.codex !== undefined ? { codex: request.codex } : {}),
160	        createdAt: now,
161	        updatedAt: now,
162	      };
163	
164	      await writs.put(writ);
165	      return writ;
166	    },
167	
168	    async show(id: string): Promise<WritDoc> {
169	      const writ = await writs.get(id);
170	      if (!writ) {
171	        throw new Error(`Writ "${id}" not found.`);
172	      }
173	      return writ;
174	    },
175	
176	    async list(filters?: WritFilters): Promise<WritDoc[]> {
177	      const where = buildWhereClause(filters);
178	      const limit = filters?.limit ?? 20;
179	      const offset = filters?.offset;
180	
181	      return writs.find({
182	        where,
183	        orderBy: ['createdAt', 'desc'],
184	        limit,
185	        ...(offset !== undefined ? { offset } : {}),
186	      });
187	    },
188	
189	    async count(filters?: WritFilters): Promise<number> {
190	      const where = buildWhereClause(filters);
191	      return writs.count(where);
192	    },
193	
194	    async link(sourceId: string, targetId: string, type: string): Promise<WritLinkDoc> {
195	      if (sourceId === targetId) {
196	        throw new Error(`Cannot link a writ to itself: "${sourceId}".`);
197	      }
198	      if (!type || !type.trim()) {
199	        throw new Error('Link type must be a non-empty string.');
200	      }
201	
202	      const source = await writs.get(sourceId);
203	      if (!source) {
204	        throw new Error(`Writ "${sourceId}" not found.`);
205	      }
206	      const target = await writs.get(targetId);
207	      if (!target) {
208	        throw new Error(`Writ "${targetId}" not found.`);
209	      }
210	
211	      const id = `${sourceId}:${targetId}:${type}`;
212	      const existing = await links.get(id);
213	      if (existing) {
214	        return existing;
215	      }
216	
217	      const doc: WritLinkDoc = {
218	        id,
219	        sourceId,
220	        targetId,
221	        type,
222	        createdAt: new Date().toISOString(),
223	      };
224	      await links.put(doc);
225	      return doc;
226	    },
227	
228	    async links(writId: string): Promise<WritLinks> {
229	      const [outbound, inbound] = await Promise.all([
230	        links.find({ where: [['sourceId', '=', writId]] }),
231	        links.find({ where: [['targetId', '=', writId]] }),
232	      ]);
233	      return { outbound, inbound };
234	    },
235	
236	    async unlink(sourceId: string, targetId: string, type: string): Promise<void> {
237	      const id = `${sourceId}:${targetId}:${type}`;
238	      await links.delete(id);
239	    },
240	
241	    async transition(id: string, to: WritStatus, fields?: Partial<WritDoc>): Promise<WritDoc> {
242	      const writ = await writs.get(id);
243	      if (!writ) {
244	        throw new Error(`Writ "${id}" not found.`);
245	      }
246	
247	      const allowedFrom = ALLOWED_FROM[to];
248	      if (!allowedFrom.includes(writ.status)) {
249	        throw new Error(
250	          `Cannot transition writ "${id}" to "${to}": status is "${writ.status}", expected one of: ${allowedFrom.join(', ')}.`,
251	        );
252	      }
253	
254	      const now = new Date().toISOString();
255	      const isTerminal = TERMINAL_STATUSES.has(to);
256	
257	      // Strip managed fields — callers cannot override id, status, or timestamps
258	      // controlled by the status machine.
259	      const { id: _id, status: _status, createdAt: _c, updatedAt: _u,
260	        acceptedAt: _a, resolvedAt: _r, ...safeFields } = (fields ?? {}) as WritDoc;
261	
262	      const patch: Partial<Omit<WritDoc, 'id'>> = {
263	        status: to,
264	        updatedAt: now,
265	        ...(to === 'active' ? { acceptedAt: now } : {}),
266	        ...(isTerminal ? { resolvedAt: now } : {}),
267	        ...safeFields,
268	      };
269	
270	      return writs.patch(id, patch);
271	    },
272	  };
273	
274	  // ── writ-types tool ──────────────────────────────────────────────
275	
276	  const writTypesTool = tool({
277	    name: 'writ-types',
278	    description: 'List available writ types for this guild',
279	    instructions:
280	      'Returns the available writ types including built-in types, types declared ' +
281	      'in guild config, and types contributed by kits. Each entry includes the ' +
282	      'type name, optional description, and whether it is the default type.',
283	    params: {},
284	    permission: 'clerk:read',
285	    handler: async () => {
286	      const config = resolveClerkConfig();
287	      const defaultType = resolveDefaultType();
288	      const configEntries = config.writTypes ?? [];
289	
290	      return [...mergedWritTypes].map((name) => {
291	        const entry = configEntries.find((e) => e.name === name);
292	        return {
293	          name,
294	          description: entry?.description ?? null,
295	          default: name === defaultType,
296	        };
297	      });
298	    },
299	  });
300	
301	  // ── Apparatus ────────────────────────────────────────────────────
302	
303	  return {
304	    apparatus: {
305	      requires: ['stacks'],
306	      recommends: ['oculus'],
307	      consumes: ['writTypes'],
308	
309	      supportKit: {
310	        books: {
311	          writs: {
312	            indexes: ['status', 'type', 'createdAt', ['status', 'type'], ['status', 'createdAt']],
313	          },
314	          links: {
315	            indexes: ['sourceId', 'targetId', 'type', ['sourceId', 'type'], ['targetId', 'type']],
316	          },
317	        },
318	        tools: [
319	          commissionPost,
320	          writShow,
321	          writList,
322	          writAccept,
323	          writComplete,
324	          writFail,
325	          writCancel,
326	          writLink,
327	          writUnlink,
328	          writTypesTool,
329	        ],
330	        pages: [
331	          { id: 'writs', title: 'Writs', dir: 'pages/writs' },
332	        ],
333	      },
334	
335	      provides: api,
336	
337	      start(ctx: StartupContext): void {
338	        const g = guild();
339	        const stacks = g.apparatus<StacksApi>('stacks');
340	        writs = stacks.book<WritDoc>('clerk', 'writs');
341	        links = stacks.book<WritLinkDoc>('clerk', 'links');
342	
343	        // Initialize merged writ types from builtins + config
344	        const config = resolveClerkConfig();
345	        configWritTypeNames = new Set((config.writTypes ?? []).map((e) => e.name));
346	        mergedWritTypes = new Set([...BUILTIN_TYPES, ...configWritTypeNames]);
347	
348	        // Phase 1a: Scan standalone kits
349	        for (const kit of g.kits()) {
350	          registerKitWritTypes(kit.id, kit.kit);
351	        }
352	
353	        // Phase 1b: Scan already-started apparatus supportKits
354	        for (const app of g.apparatuses()) {
355	          if (app.apparatus.supportKit) {
356	            registerKitWritTypes(app.id, app.apparatus.supportKit);
357	          }
358	        }
359	
360	        // Phase 2: Subscribe for late-arriving apparatus supportKits
361	        ctx.on('plugin:initialized', (plugin: unknown) => {
362	          const loaded = plugin as LoadedPlugin;
363	          if (isLoadedApparatus(loaded) && loaded.apparatus.supportKit) {
364	            registerKitWritTypes(loaded.id, loaded.apparatus.supportKit);
365	          }
366	        });
367	      },
368	    },
369	  };
370	}
