129	
130	  const orderedApparatuses = topoSort(apparatuses);
131	  const provides = new Map<string, unknown>();
132	
133	  // Wire guild singleton before any apparatus starts so start() methods
134	  // can call guild(). The provides Map is populated progressively as each
135	  // apparatus starts; dependency ordering guarantees declared deps are
136	  // available.
137	
138	  const guildInstance: Guild = {
139	    home: guildRoot,
140	
141	    apparatus<T>(name: string): T {
142	      const p = provides.get(name);
143	      if (p === undefined) {
144	        throw new Error(
145	          `[guild] apparatus("${name}") is not available. ` +
146	          `No loaded apparatus provides this id. Check guild.json plugins list.`,
147	        );
148	      }
149	      return p as T;
150	    },
151	
152	    config<T = Record<string, unknown>>(pluginId: string): T {
153	      // GuildConfig types only the framework-level keys (name, nexus, plugins, etc.).
154	      // Plugin-specific config sections (e.g. "animator", "stacks") are additional
155	      // top-level keys in guild.json that GuildConfig doesn't model. The cast is safe
156	      // because guild.json is a plain JSON object — all keys are accessible at runtime.
157	      // Plugins can use module augmentation on GuildConfig to get typed access; this
158	      // generic path remains the untyped fallback.
159	      const cfg = config as unknown as Record<string, unknown>;
160	      return (cfg[pluginId] ?? {}) as T;
161	    },
162	
163	    writeConfig<T = Record<string, unknown>>(pluginId: string, value: T): void {
164	      // Update the in-memory config so subsequent reads reflect the change,
165	      // then persist to disk. The cast is the same pattern as config() above.
166	      const cfg = config as unknown as Record<string, unknown>;
167	      cfg[pluginId] = value;
168	      writeGuildConfig(guildRoot, config);
169	    },
170	
171	    guildConfig() {
172	      return config;
173	    },
174	
175	    kits()             { return [...kits]; },
176	    apparatuses()      { return [...orderedApparatuses]; },
177	    failedPlugins()    { return [...allFailures]; },
178	    startupWarnings()  { return [...allWarnings]; },
179	  };
180	  setGuild(guildInstance);
181	
