183	  for (const kit of kits) {
184	    await fireEvent(eventHandlers, 'plugin:initialized', kit);
185	  }
186	
187	  // Start each apparatus in dependency order
188	  const startupCtx = buildStartupContext(eventHandlers);
189	  for (const app of orderedApparatuses) {
190	    // Register provides before start() so apparatuses with eager provides are
191	    // visible to later startups that run during this loop.
192	    if (app.apparatus.provides !== undefined) {
193	      provides.set(app.id, app.apparatus.provides);
194	    }
